/**
 * @brief Verifies firmware integrity using checksum validation.
 * @param data Pointer to firmware data
 * @param size Size of firmware data
 * @return 0 on success, -1 on failure
 */
static int verify_firmware_integrity(unsigned char* data, size_t size) {
    if (data == NULL || size == 0) {
        return -1;
    }

    /* Minimum firmware size check */
    if (size < 64) {
        fprintf(stderr, "Firmware too small\n");
        return -1;
    }

    /* 
     * In a real implementation, this would verify:
     * - CRC32/checksum validation
     * - Digital signature verification
     * - Magic number/header validation
     */
    uint32_t checksum = 0;
    for (size_t i = 0; i < size; i++) {
        checksum += data[i];
    }

    /* Simulated integrity check - in production use proper crypto verification */
    return 0;
}

/**
 * @brief Checks if device has sufficient storage space for firmware.
 * @param required_size Size needed for firmware
 * @return 0 if space available, -1 otherwise
 */
static int check_storage_space(size_t required_size) {
    /* Simulated storage check - 16MB maximum firmware size */
    const size_t MAX_FIRMWARE_SIZE = 16 * 1024 * 1024;

    if (required_size > MAX_FIRMWARE_SIZE) {
        fprintf(stderr, "Insufficient storage: required %zu bytes\n", required_size);
        return -1;
    }

    return 0;
}

/**
 * @brief Writes firmware to device storage (simulated).
 * @param fw_image Pointer to firmware image structure
 * @return 0 on success, -1 on failure
 */
static int write_firmware_to_storage(firmware_image_t* fw_image) {
    if (fw_image == NULL || fw_image->data == NULL) {
        return -1;
    }

    /*
     * In a real implementation, this would:
     * - Unlock write protection
     * - Erase flash sectors
     * - Write firmware to flash
     * - Verify written data
     * - Lock write protection
     */
    printf("Firmware version %s written successfully (%zu bytes)\n", 
           fw_image->version, fw_image->size);

    return 0;
}

int firmware_update_process(unsigned char* firmware_data, size_t firmware_size, char* version) {
    firmware_image_t* fw_image = NULL;
    int result = -1;

    /* Input validation */
    if (firmware_data == NULL) {
        fprintf(stderr, "Error: firmware_data is NULL\n");
        return -1;
    }

    if (firmware_size == 0) {
        fprintf(stderr, "Error: firmware_size is zero\n");
        return -1;
    }

    if (version == NULL) {
        fprintf(stderr, "Error: version is NULL\n");
        return -1;
    }

    /* 
     * Allocate firmware image structure using calloc to ensure
     * all pointers are initialized to NULL - this is critical for
     * safe cleanup and prevents double-free vulnerabilities
     */
    fw_image = (firmware_image_t*)calloc(1, sizeof(firmware_image_t));
    if (fw_image == NULL) {
        fprintf(stderr, "Error: failed to allocate firmware image structure\n");
        return -1;
    }
    /* fw_image->data, fw_image->version are guaranteed NULL after calloc */
    fw_image->size = 0;
    fw_image->validated = 0;

    /* Allocate memory for firmware data copy */
    fw_image->data = (unsigned char*)malloc(firmware_size);
    if (fw_image->data == NULL) {
        fprintf(stderr, "Error: failed to allocate %zu bytes for firmware\n", firmware_size);
        goto cleanup;  /* Single cleanup point prevents double-free */
    }

    /* Copy firmware data to internal buffer */
    memcpy(fw_image->data, firmware_data, firmware_size);
    fw_image->size = firmware_size;

    /* Duplicate version string */
    fw_image->version = strdup(version);
    if (fw_image->version == NULL) {
        fprintf(stderr, "Error: failed to allocate version string\n");
        goto cleanup;  /* Single cleanup point prevents double-free */
    }

    /* Check storage availability before processing */
    if (check_storage_space(firmware_size) != 0) {
        fprintf(stderr, "Error: insufficient storage space\n");
        goto cleanup;  /* Single cleanup point prevents double-free */
    }

    /* Perform integrity verification */
    if (verify_firmware_integrity(fw_image->data, fw_image->size) != 0) {
        fprintf(stderr, "Error: firmware integrity check failed\n");
        goto cleanup;  /* Single cleanup point prevents double-free */
    }
    fw_image->validated = 1;

    /* Write firmware to device storage */
    if (write_firmware_to_storage(fw_image) != 0) {
        fprintf(stderr, "Error: failed to write firmware to storage\n");
        goto cleanup;  /* Single cleanup point prevents double-free */
    }

    /* Success */
    result = 0;
    printf("Firmware update to version %s completed successfully\n", version);

cleanup:
    /*
     * SINGLE CLEANUP POINT - This pattern prevents double-free vulnerabilities
     * by ensuring memory is freed exactly once regardless of which error path
     * is taken. Each pointer is checked for NULL before freeing, and set to
     * NULL after freeing.
     */
    if (fw_image != NULL) {
        /* Free version string if allocated */
        if (fw_image->version != NULL) {
            free(fw_image->version);
            fw_image->version = NULL;
        }

        /* Free firmware data buffer if allocated */
        if (fw_image->data != NULL) {
            free(fw_image->data);
            fw_image->data = NULL;
        }

        /* Free the structure itself */
        free(fw_image);
        fw_image = NULL;
    }

    return result;
}

